#include <openssl/evp.h>

void strongEncryption() {
    // Compliant: Using strong AES-256 with CBC mode
    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
    EVP_EncryptInit_ex(ctx, EVP_aes_256_cbc(), NULL, key, iv);

    // Compliant: Using GCM mode for authenticated encryption
    EVP_EncryptInit_ex(ctx, EVP_aes_256_gcm(), NULL, key, iv);

    // Compliant: Using proper padding (PKCS7 by default)
    EVP_CIPHER_CTX_set_padding(ctx, 1);

    // Compliant: ChaCha20-Poly1305 for modern security
    EVP_EncryptInit_ex(ctx, EVP_chacha20_poly1305(), NULL, key, iv);
}
